SELECT /*+ INDEX_DESC(A PPS_RCG_IDX1) */ SEQ, SUBSCRIBER_NO, NVL(DECODE(CONTRACT_NUM, 0, '', CONTRACT_NUM),'') CONTRACT_NUM, NVL(REQ_SRC,'') REQ_SRC, NVL(REQ_TYPE,'') REQ_TYPE, NVL(RECHARGE_INFO,'') RECHARGE_INFO, NVL(RECHARGE_METHOD,'') RECHARGE_METHOD, NVL(AMOUNT,0) AMOUNT, NVL(IN_AMOUNT,0) IN_AMOUNT, NVL(KT_RES_CODE,'') KT_RES_CODE, DECODE(KT_RES_CODE,'0000', '성공', '', '', '실패') KT_RES_CODE_NM, NVL(TO_CHAR(KT_RES_DT, 'YYYY-MM-DD HH24:MI:SS'),'') KT_RES_DT, NVL(ADMIN_ID, '') ADMIN_ID, NVL(F_GET_ADMIN_NM(ADMIN_ID),'') ADMIN_NM, NVL(RECHARGE_AGENT,'') RECHARGE_AGENT, NVL(F_GET_AGENT_NM(RECHARGE_AGENT),'') RECHARGE_AGENT_NAME, NVL(CHG_TYPE,'') CHG_TYPE, NVL(F_GET_KT_CODE_NM('PPS_RCG','CHG_TYPE',CHG_TYPE),'') CHG_TYPE_NAME, NVL(CANCEL_FLAG,'') CANCEL_FLAG, NVL(TO_CHAR(CANCEL_DT,'YYYY-MM-DD'),'') CANCEL_DT, NVL(BASIC_REMAINS,0) BASIC_REMAINS, NVL(TO_CHAR(RECHARGE_DATE, 'YYYY-MM-DD HH24:MI:SS'),'') RECHARGE_DATE, DECODE(CANCEL_FLAG, 'N', DECODE(KT_RES_CODE, '0000', DECODE(REQ_TYPE, 'BS_REMAINS_EDIT', '', '취소'), ''), '') CANCEL_BTN, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'),'') BASIC_EXPIRE, DECODE(KT_RES_CODE, '0000', '', DECODE(REMARK, '', NVL(F_GET_KT_CODE_NM('PPS_KT_IN_RES', 'RES_CODE', KT_RES_CODE), ''), REMARK)) REMARK, FREE_FLAG, DECODE(FREE_FLAG,'N','판매', 'Y','수수료', '-') FREE_FLAG_NM , F_GET_AGENT_NM((SELECT AGENT_ID FROM PPS_CUSTOMER WHERE CONTRACT_NUM = A.CONTRACT_NUM)) OPEN_AGENT_NM, DECODE((SELECT AGENT_SALE_ID FROM PPS_CUSTOMER WHERE CONTRACT_NUM = A.CONTRACT_NUM), '', '', F_GET_AGENT_NM((SELECT AGENT_SALE_ID FROM PPS_CUSTOMER WHERE CONTRACT_NUM = A.CONTRACT_NUM))) OPEN_AGENT_SALE_NM, (SELECT LST_COM_ACTV_DATE FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM) AS LST_COM_ACTV_DATE, (SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = (SELECT SOC FROM PPS_CUSTOMER WHERE CONTRACT_NUM = A.CONTRACT_NUM) and rownum = 1) AS SOC_NM FROM PPS_RCG A WHERE RECHARGE_DATE > TO_DATE('2010-01-01','YYYY-MM-DD') AND RECHARGE_DATE < SYSDATE
