AND RECHARGE_INFO = #{searchSValue}
AND AGENT_ID = #{searchAgentId}
AND RECHARGE_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND RECHARGE_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND REQ_SRC = #{searchReqSrc}
AND CHG_TYPE = #{searchChgType}
