SELECT /*+ INDEX_DESC(A PPS_RCG_POS_IDX2) */ POS_SEQ, STORE_CODE, F_GET_AGENT_NM(STORE_CODE) STORE_CODE_NM, AUTH_CODE, REQ_TYPE, NVL((SELECT B.CD_TXT AS REQ_TYPE_NM FROM PPS_CODE_COMBO B WHERE B.LOV_CD='PPS0061' AND B.CD_VAL =REQ_TYPE),'') AS REQ_TYPE_NM, CONTRACT_NUM, SUBSCRIBER_NO, AMOUNT, TO_CHAR(RECORD_DATE,'YYYY-MM-DD HH24:MI:SS') RECORD_DATE, RET_CODE, F_GET_KT_CODE_NM('PPS_RCG_POS','RET_CODE',RET_CODE) RET_CODE_NM, CANCEL_FLAG, TO_CHAR(CANCEL_DATE,'YYYY-MM-DD') CANCEL_DATE , RCG_SEQ FROM PPS_RCG_POS A WHERE RECORD_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
