AND CANCEL_FLAG = 'N'

SELECT /*+ INDEX_DESC(A PPS_RCG_POS_IDX2) */ NVL(POS_SEQ,0) POSSEQ, NVL(STORE_CODE,'-') STORECODE, NVL(F_GET_AGENT_NM(STORE_CODE),'-') STORECODENM, NVL(AUTH_CODE,'-') AUTHCODE, NVL(REQ_TYPE,'-') REQTYPE, NVL((SELECT B.CD_TXT AS REQ_TYPE_NM FROM PPS_CODE_COMBO B WHERE B.LOV_CD='PPS0061' AND B.CD_VAL =REQ_TYPE),'-') AS REQTYPENM, NVL(CONTRACT_NUM,'-') CONTRACTNUM, NVL(SUBSCRIBER_NO,'-') SUBSCRIBERNO, NVL(AMOUNT,0) AMOUNT, NVL(TO_CHAR(RECORD_DATE,'YYYY-MM-DD HH24:MI:SS'),'-') RECORDDATE, NVL(RET_CODE,'-') RETCODE, NVL(F_GET_KT_CODE_NM('PPS_RCG_POS','RET_CODE',RET_CODE),'-') RETCODENM, NVL(CANCEL_FLAG,'-') CANCELFLAG, NVL(TO_CHAR(CANCEL_DATE,'YYYY-MM-DD'),'-') CANCELDATE , NVL(RCG_SEQ,0) RCGSEQ FROM PPS_RCG_POS A WHERE RECORD_DATE > TO_DATE('1900-01-01','YYYY-MM-DD')
AND CONTRACT_NUM = #{searchNm}
AND CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
