AND RECORD_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND CANCEL_FLAG = 'Y'
AND CANCEL_FLAG = 'N'

SELECT B.CONTRACT_NUM CONTRACT_NUM, B.BAN AS CUSTOMER_BAN, A.SOC, AD_SSN, (SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1) SERVICE_NAME, A.SERVICE_TYPE, F_GET_KT_CODE_NM('PPS_CUSTOMER','SERVICE_TYPE',A.SERVICE_TYPE) SERVICE_TYPE_NAME, PAPER_IMAGE_1, PAPER_IMAGE_2, PAPER_IMAGE_3, PAPER_IMAGE_4, PAPER_IMAGE_5, DECODE(paper_Image_1,'','X','O' ) || DECODE(paper_Image_2,'','X','O' ) || DECODE(paper_Image_3,'','X','O' ) || DECODE(paper_Image_4,'','X','O' ) || DECODE(paper_Image_5,'','X','O' ) AS PAPER_IMAGE, AGENT_ID, FN_GET_ORGNM(AGENT_ID) AGENT_NAME, VIR_ACCOUNT_ID, BASIC_REMAINS, TO_CHAR(A.LAST_BASIC_CHG_DT,'YYYY-MM-DD') LAST_BASIC_CHG_DT, TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD') BASIC_EXPIRE, TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD') BASIC_EMPT_DT, TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS') ENTER_DATE, LANG_CODE, AD_NATION, DECODE(AD_NATION,'','미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)) AD_NATION_NM, B.CUSTOMER_ID, B.SUBSCRIBER_NO, B.SUB_STATUS, F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS) SUB_STATUS_NAME, USER_SSN, B.SUB_LINK_NAME AS SUB_LINK_NAME, B.MODEL_NAME AS MODEL_NAME, B.MODEL_ID AS MODEL_ID, B.BAN AS BAN, B.LST_COM_ACTV_DATE, A.CMS_CHARGE_TYPE AS CMS_CHARGE_TYPE, NVL(A.AGENT_SALE_ID,'-') AGENT_SALE_ID , NVL(FN_GET_ORGNM(AGENT_SALE_ID),'-') AGENT_SALE_NM, TO_CHAR(A.STATUS_STOP_DT, 'YYYY-MM-DD') STATUS_STOP_DT, NVL(D.RECHARGE_CNT, 0) RECHARGE_CNT, NVL(D.RECHARGE_SUM, 0) RECHARGE_SUM FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B, MSP_RATE_MST C, (SELECT COUNT(*) RECHARGE_CNT, SUM(AMOUNT) RECHARGE_SUM, CONTRACT_NUM FROM PPS_RCG WHERE KT_RES_CODE = '0000' AND CANCEL_FLAG = 'N' GROUP BY CONTRACT_NUM ) D WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.SOC = C.RATE_CD AND A.CONTRACT_NUM = D.CONTRACT_NUM(+) AND ENTER_DATE > TO_DATE('1900-01-01','YYYY-MM-DD') AND ENTER_DATE < SYSDATE AND B.SUB_STATUS IN ('A','S') AND C.PAY_CL_CD = 'PP' AND A.CONTRACT_NUM NOT IN(SELECT SERVICE_ACCOUNT FROM PPS_RCG_REMOTE_REQ)
AND A.CONTRACT_NUM = #{searchNm}
AND B.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND A.AGENT_ID IS NULL
AND A.AGENT_ID = #{searchAgentId}
AND A.ENTER_DATE >= TO_DATE(#{startOpenDt}, 'YYYY-MM-DD')
AND A.ENTER_DATE < TO_DATE(#{endOpenDt}, 'YYYY-MM-DD')+1
AND A.STATUS_STOP_DT >= TO_DATE(#{startStopDt}, 'YYYY-MM-DD')
AND A.STATUS_STOP_DT < TO_DATE(#{endStopDt}, 'YYYY-MM-DD')+1
AND A.BASIC_EXPIRE >= TO_DATE(#{startExpireDt}, 'YYYY-MM-DD')
AND A.BASIC_EXPIRE < TO_DATE(#{endExpireDt}, 'YYYY-MM-DD')+1
AND A.BASIC_REMAINS = 0
AND A.BASIC_REMAINS > 0
AND A.BASIC_REMAINS >= #{startRemains}
AND A.BASIC_REMAINS <= #{endRemains}
AND SOC = #{searchFeatures}
AND B.SUB_STATUS = #{subStatus}

	{CALL P_RCG_BATCH (#{opCode, jdbcType=VARCHAR},#{contractNumArr, jdbcType=VARCHAR}, #{reqType, jdbcType=VARCHAR}, #{paramCnt, jdbcType=VARCHAR}, #{recharge, jdbcType=VARCHAR}, #{title, jdbcType=VARCHAR},#{ip, jdbcType=VARCHAR}, #{adminId, jdbcType=VARCHAR},
	 #{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR},
	 #{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
		)
     }

SELECT NVL(B.CONTRACT_NUM,0) CONTRACTNUM, NVL(B.BAN,'-') AS CUSTOMERBAN, NVL(A.SOC,'-') SOC, NVL(AD_SSN,'-') ADSSN, NVL((SELECT RATE_NM SERVICE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC and rownum = 1),'-') SERVICENAME, NVL(A.SERVICE_TYPE,'-') SERVICETYPE, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER','SERVICE_TYPE',A.SERVICE_TYPE),'-') SERVICETYPENAME, NVL(PAPER_IMAGE_1,'-') PAPERIMAGE1, NVL(PAPER_IMAGE_2,'-') PAPERIMAGE2, NVL(PAPER_IMAGE_3,'-') PAPERIMAGE3, NVL(PAPER_IMAGE_4,'-') PAPERIMAGE4, NVL(PAPER_IMAGE_5,'-') PAPERIMAGE5, DECODE(paper_Image_1,'','X','O' ) || DECODE(paper_Image_2,'','X','O' ) || DECODE(paper_Image_3,'','X','O' ) || DECODE(paper_Image_4,'','X','O' ) || DECODE(paper_Image_5,'','X','O' ) AS PAPERIMAGE, NVL(AGENT_ID, '-') AGENTID, NVL(FN_GET_ORGNM(AGENT_ID),'-') AGENTNAME, NVL(VIR_ACCOUNT_ID,'-') VIRACCOUNTID, NVL(BASIC_REMAINS,0) BASICREMAINS, NVL(TO_CHAR(A.LAST_BASIC_CHG_DT,'YYYY-MM-DD'),'-') LASTBASICCHGDT, NVL(TO_CHAR(BASIC_EXPIRE, 'YYYY-MM-DD'),'-') BASICEXPIRE, NVL(TO_CHAR(BASIC_EMPT_DT, 'YYYY-MM-DD'),'-') BASICEMPTDT, NVL(TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS'),'-') ENTERDATE, NVL(LANG_CODE,'-') LANGCODE, NVL(AD_NATION,'-') ADNATION, DECODE(AD_NATION,'','미등록', F_GET_KT_CODE_NM('PPS_CUSTOMER', 'AD_NATION', AD_NATION)) ADNATIONNM, NVL(B.CUSTOMER_ID,'-') CUSTOMERID, NVL(B.SUBSCRIBER_NO,'-') SUBSCRIBERNO, NVL(B.SUB_STATUS,'-') SUBSTATUS, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER','SUB_STATUS',B.SUB_STATUS),'-') SUBSTATUSNAME, NVL(USER_SSN,'-') USERSSN, NVL(B.SUB_LINK_NAME,'-') AS SUBLINKNAME, NVL(B.MODEL_NAME,'-') AS MODELNAME, NVL(B.MODEL_ID,'-') AS MODELID, NVL(B.BAN,'-') AS BAN, NVL(B.LST_COM_ACTV_DATE,'-') LSTCOMACTVDATE, NVL(A.CMS_CHARGE_TYPE,'-') AS CMSCHARGETYPE, NVL(A.AGENT_SALE_ID,'-') AGENTSALEID , NVL(FN_GET_ORGNM(AGENT_SALE_ID),'-') AGENTSALENM, NVL(TO_CHAR(A.STATUS_STOP_DT, 'YYYY-MM-DD'),'-') STATUSSTOPDT, NVL(D.RECHARGE_CNT, 0) RECHARGE_CNT, NVL(D.RECHARGE_SUM, 0) RECHARGE_SUM FROM PPS_CUSTOMER A, MSP_JUO_SUB_INFO B, MSP_RATE_MST C, (SELECT COUNT(*) RECHARGE_CNT, SUM(AMOUNT) RECHARGE_SUM, CONTRACT_NUM FROM PPS_RCG WHERE KT_RES_CODE = '0000' AND CANCEL_FLAG = 'N' GROUP BY CONTRACT_NUM ) D WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.SOC = C.RATE_CD AND A.CONTRACT_NUM = D.CONTRACT_NUM(+) AND ENTER_DATE > TO_DATE('1900-01-01','YYYY-MM-DD') AND ENTER_DATE < SYSDATE AND B.SUB_STATUS IN ('A','S') AND C.PAY_CL_CD = 'PP' AND A.CONTRACT_NUM NOT IN(SELECT SERVICE_ACCOUNT FROM PPS_RCG_REMOTE_REQ)
AND A.CONTRACT_NUM = #{searchNm}
AND B.CONTRACT_NUM = (select F_GET_LIKE_CTN2_CONTRACT_NUM(#{searchNm}) from dual)
AND A.AGENT_ID IS NULL
AND A.AGENT_ID = #{searchAgentId}
AND A.ENTER_DATE >= TO_DATE(#{startOpenDt}, 'YYYY-MM-DD')
AND A.ENTER_DATE < TO_DATE(#{endOpenDt}, 'YYYY-MM-DD')+1
AND A.STATUS_STOP_DT >= TO_DATE(#{startStopDt}, 'YYYY-MM-DD')
AND A.STATUS_STOP_DT < TO_DATE(#{endStopDt}, 'YYYY-MM-DD')+1
AND A.BASIC_EXPIRE >= TO_DATE(#{startExpireDt}, 'YYYY-MM-DD')
AND A.BASIC_EXPIRE < TO_DATE(#{endExpireDt}, 'YYYY-MM-DD')+1
AND A.BASIC_REMAINS = 0
AND A.BASIC_REMAINS > 0
AND A.BASIC_REMAINS >= #{startRemains}
AND A.BASIC_REMAINS <= #{endRemains}
AND SOC = #{searchFeatures}
AND B.SUB_STATUS = #{subStatus}

	{CALL P_VAC (#{opCode, jdbcType=VARCHAR}, #{opMode, jdbcType=VARCHAR}, #{userType, jdbcType=VARCHAR}, #{reqBankName, jdbcType=VARCHAR}, #{userNumber, jdbcType=VARCHAR}, #{adminId, jdbcType=VARCHAR},
	 #{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR},
	 #{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
		)
     }

	{call p_rcg_bill(
			    #{opCode, jdbcType=VARCHAR}
			    , #{seq, jdbcType=VARCHAR}
			    , #{reqType, jdbcType=VARCHAR}
			    , #{subscriberNo, jdbcType=VARCHAR}
			    , #{recharge, jdbcType=VARCHAR}
			    , #{rechargeInfo, jdbcType=VARCHAR}
			    , #{agentId, jdbcType=VARCHAR}
			    , #{adminId, jdbcType=VARCHAR}
			    , #{ip, jdbcType=VARCHAR}
			    , #{dataVaId, jdbcType=VARCHAR}
			    , #{topupGubun, jdbcType=VARCHAR}
			   ,#{seq, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   ,#{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   ,#{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
			  )
     }

	{call P_AGENT_DEPOSIT(
			    #{opCode, jdbcType=VARCHAR}
			    , #{agentId, jdbcType=VARCHAR}
			    , #{depositType, jdbcType=VARCHAR}
			    , #{plusDeposit, jdbcType=VARCHAR}
			    , #{remark, jdbcType=VARCHAR}
			    , #{adminId, jdbcType=VARCHAR}
			   ,#{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   ,#{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
			  )
     }

SELECT /*+ INDEX_DESC(A PPS_KT_FTP_ATM_RCG_IDX1) */ TO_CHAR(TO_DATE(TR_TIME, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') TR_TIME, CONTRACT_NUM, REQ_TEL_NO, PAY_CODE, F_GET_KT_CODE_NM('KT_FTP_ATM_RCG', 'PAY_CODE', PAY_CODE) PAY_CODE_NM, REFILL_CHARGE, STATUS, DECODE(STATUS, '99', '충전성공', '충전실패') STATUS_NM, R_CODE, F_GET_KT_CODE_NM('PPS_KT_FTP_ATM_RCG', 'R_CODE', R_CODE) R_CODE_NM, PRE_BALANCE, POST_BALANCE, TO_CHAR(TO_DATE(PRE_BAL_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') PRE_BAL_DATE, TO_CHAR(TO_DATE(POST_BAL_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') POST_BAL_DATE, PIN_NO, TR_NO, NH_CODE, CA_NAME, PROC_RET_CD, PROC_RET_MSG, TO_CHAR(RECORD_DATE, 'YY/MM/DD HH24:MI') RECORD_DATE FROM PPS_KT_FTP_ATM_RCG A WHERE 1=1
AND CONTRACT_NUM = #{searchNm}
AND PIN_NO = #{searchNm}
AND REQ_TEL_NO = #{searchNm}
AND TR_NO = #{searchNm}
AND TR_TIME >= REPLACE(#{startDt}, '-', '')
AND TR_TIME <= REPLACE(#{endDt} || '999999', '-', '')
AND STATUS = '99'
AND STATUS <> '99'
AND PROC_RET_CD = '0000'
AND PROC_RET_CD <> '0000'

SELECT /*+ INDEX_DESC(A PPS_KT_FTP_ATM_RCG_IDX1) */ NVL(TO_CHAR(TO_DATE(TR_TIME, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS'), '-') TR_TIME, NVL(CONTRACT_NUM, '-') CONTRACT_NUM, NVL(REQ_TEL_NO, '-') SUBSCRIBER_NO, NVL(PAY_CODE, '-') PAY_CODE, NVL(F_GET_KT_CODE_NM('KT_FTP_ATM_RCG', 'PAY_CODE', PAY_CODE), '-') PAY_CODE_NM, NVL(REFILL_CHARGE, 0) REFILL_CHARGE, NVL(STATUS, '-') STATUS, NVL(DECODE(STATUS, '99', '충전성공', '충전실패'), '-') STATUS_NM, NVL(R_CODE, '-') R_CODE, NVL(F_GET_KT_CODE_NM('PPS_KT_FTP_ATM_RCG', 'R_CODE', R_CODE), '-') R_CODE_NM, NVL(PRE_BALANCE, 0) PRE_BALANCE, NVL(POST_BALANCE, 0) POST_BALANCE, NVL(TO_CHAR(TO_DATE(PRE_BAL_DATE, 'YYYYMMDD'), 'YYYY-MM-DD'), '-') PRE_BAL_DATE, NVL(TO_CHAR(TO_DATE(POST_BAL_DATE, 'YYYYMMDD'), 'YYYY-MM-DD'), '-') POST_BAL_DATE, NVL(PIN_NO, '-') PIN_NO, NVL(TR_NO, '-') TR_NO, NVL(NH_CODE, '-') NH_CODE, NVL(CA_NAME, '-') CA_NAME, NVL(PROC_RET_CD, '-') CA_NAME, NVL(PROC_RET_MSG, '-') PROC_RET_MSG, NVL(TO_CHAR(RECORD_DATE, 'YY/MM/DD HH24:MI'), '-') RECORD_DATE FROM PPS_KT_FTP_ATM_RCG A WHERE 1=1
AND CONTRACT_NUM = #{searchNm}
AND PIN_NO = #{searchNm}
AND REQ_TEL_NO = #{searchNm}
AND TR_NO = #{searchNm}
AND TR_TIME >= REPLACE(#{startDt}, '-', '')
AND TR_TIME <= REPLACE(#{endDt} || '999999', '-', '')
AND STATUS = '99'
AND STATUS <> '99'
AND PROC_RET_CD = '0000'
